import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Helmet } from 'react-helmet-async';
import { loadStripe } from '@stripe/stripe-js';
import { Elements, PaymentElement, useStripe, useElements } from '@stripe/react-stripe-js';
import { Lock, ShieldCheck } from 'lucide-react';
import toast from 'react-hot-toast';
import { useCart } from '../context/CartContext';
import { apiMessage } from '../lib/api';
import LoadingSpinner from '../components/LoadingSpinner';

const pk = process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY || '';
const stripePromise = pk ? loadStripe(pk) : null;

function CheckoutPaymentForm({ shippingAddress, onSuccess }) {
  const stripe = useStripe();
  const elements = useElements();
  const [busy, setBusy] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!stripe || !elements) return;
    setBusy(true);
    try {
      const { error, paymentIntent } = await stripe.confirmPayment({
        elements,
        confirmParams: {
          return_url: `${window.location.origin}/account/orders`
        },
        redirect: 'if_required'
      });
      if (error) {
        toast.error(error.message || 'Payment failed');
        return;
      }
      const pi = paymentIntent;
      if (!pi?.id) {
        toast.error('Payment was not completed');
        return;
      }
      const confirmRes = await axios.post(
        '/api/orders/confirm',
        {
          paymentIntentId: pi.id,
          shippingAddress
        },
        { withCredentials: true }
      );
      toast.success('Order placed — thank you!');
      onSuccess();
      const orderId = confirmRes?.data?.data?.order?._id;
      navigate(orderId ? `/order-confirmation/${orderId}` : '/account/orders');
    } catch (err) {
      toast.error(apiMessage(err, 'Could not complete order'));
    } finally {
      setBusy(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="checkout-payment-form">
      <PaymentElement />
      <button type="submit" className="btn btn-gold btn-full checkout-pay-btn" disabled={!stripe || busy}>
        {busy ? 'Processing…' : 'Pay securely'}
      </button>
    </form>
  );
}

export default function Checkout() {
  const navigate = useNavigate();
  const { cart, cartState, loading, fetchCart, getSubtotal } = useCart();
  const [deliveryOption, setDeliveryOption] = useState('standard');
  const [shippingAddress, setShippingAddress] = useState({
    firstName: '',
    lastName: '',
    street: '',
    city: '',
    state: '',
    zipCode: '',
    country: 'United Kingdom',
    phone: ''
  });
  const [clientSecret, setClientSecret] = useState(null);
  const [creatingPi, setCreatingPi] = useState(false);

  const totals = cartState.totals;
  const step = clientSecret ? 2 : 1;

  const startPayment = async () => {
    if (!cart.length) {
      toast.error('Your cart is empty');
      return;
    }
    if (!stripePromise) {
      toast.error('Stripe is not configured. Set REACT_APP_STRIPE_PUBLISHABLE_KEY in .env');
      return;
    }
    setCreatingPi(true);
    try {
      const res = await axios.post(
        '/api/stripe/create-payment-intent',
        {
          deliveryOption,
          shippingAddress
        },
        { withCredentials: true }
      );
      const secret = res.data?.data?.clientSecret;
      if (!secret) {
        toast.error(res.data?.message || 'Could not start payment');
        return;
      }
      setClientSecret(secret);
      toast.success('Enter your card details below');
    } catch (err) {
      toast.error(apiMessage(err, 'Payment setup failed'));
    } finally {
      setCreatingPi(false);
    }
  };

  const handlePaidSuccess = () => {
    fetchCart();
  };

  if (loading) {
    return (
      <main className="section container checkout-page checkout-page--loading" id="main-content">
        <Helmet>
          <title>Checkout | Nova Shop</title>
        </Helmet>
        <LoadingSpinner size="lg" label="Loading checkout" />
        <p className="checkout-loading-note">Loading your cart…</p>
      </main>
    );
  }

  if (!cart.length) {
    return (
      <main className="section container text-center checkout-page checkout-page--empty" id="main-content">
        <Helmet>
          <title>Checkout | Nova Shop</title>
          <meta name="description" content="Your Nova Shop cart is empty. Continue shopping to checkout." />
        </Helmet>
        <h1 className="checkout-empty-title">Your cart is empty</h1>
        <p className="checkout-empty-lead">Add something you love before checking out.</p>
        <Link to="/shop" className="btn btn-primary">
          Continue shopping
        </Link>
        <p className="checkout-empty-cart-link">
          <Link to="/cart">View cart</Link>
        </p>
      </main>
    );
  }

  return (
    <main className="section checkout-page" id="main-content">
      <Helmet>
        <title>Checkout | Nova Shop</title>
        <meta
          name="description"
          content="Complete your Nova Shop order — enter delivery details and pay securely with Stripe."
        />
        <meta property="og:title" content="Checkout | Nova Shop" />
      </Helmet>
      <div className="container">
        <header className="page-header checkout-page-header">
          <h1 className="page-header__title">Checkout</h1>
          <p className="page-header__subtitle">Delivery details, then secure card payment.</p>
          <ol className="breadcrumb" aria-label="Breadcrumb">
            <li>
              <Link to="/">Home</Link>
            </li>
            <li>
              <Link to="/cart">Cart</Link>
            </li>
            <li className="active" aria-current="page">
              Checkout
            </li>
          </ol>
        </header>

        <div className="checkout-steps" aria-label="Checkout progress">
          <span className={`checkout-steps__item ${step === 1 ? 'is-active' : ''}`}>
            <span aria-hidden>1.</span> Delivery
          </span>
          <span aria-hidden>→</span>
          <span className={`checkout-steps__item ${step === 2 ? 'is-active' : ''}`}>
            <span aria-hidden>2.</span> Payment
          </span>
        </div>

        {!pk && (
          <div className="api-error-banner" role="alert">
            <p>
              <strong>Stripe publishable key missing.</strong> Add{' '}
              <code>REACT_APP_STRIPE_PUBLISHABLE_KEY</code> to <code>frontend/.env</code> and restart the dev server.
            </p>
          </div>
        )}

        <div className="checkout-layout">
          <div className="checkout-shipping card-like">
            <h2 className="checkout-card-title">Delivery</h2>
            <div className="form-group">
              <label className="form-label">Option</label>
              <div className="delivery-options">
                {[
                  ['standard', 'Standard (3–5 days)'],
                  ['express', 'Express (1–2 days)'],
                  ['nextday', 'Next day']
                ].map(([val, label]) => (
                  <label key={val} className="delivery-option-label">
                    <input
                      type="radio"
                      name="delivery"
                      value={val}
                      checked={deliveryOption === val}
                      onChange={() => setDeliveryOption(val)}
                    />
                    {label}
                  </label>
                ))}
              </div>
            </div>
            <h3 className="checkout-subheading">Shipping address</h3>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label" htmlFor="co-first">
                  First name
                </label>
                <input
                  id="co-first"
                  className="form-control"
                  autoComplete="given-name"
                  value={shippingAddress.firstName}
                  onChange={(e) => setShippingAddress((s) => ({ ...s, firstName: e.target.value }))}
                />
              </div>
              <div className="form-group">
                <label className="form-label" htmlFor="co-last">
                  Last name
                </label>
                <input
                  id="co-last"
                  className="form-control"
                  autoComplete="family-name"
                  value={shippingAddress.lastName}
                  onChange={(e) => setShippingAddress((s) => ({ ...s, lastName: e.target.value }))}
                />
              </div>
            </div>
            <div className="form-group">
              <label className="form-label" htmlFor="co-street">
                Street
              </label>
              <input
                id="co-street"
                className="form-control"
                autoComplete="street-address"
                value={shippingAddress.street}
                onChange={(e) => setShippingAddress((s) => ({ ...s, street: e.target.value }))}
              />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label" htmlFor="co-city">
                  City
                </label>
                <input
                  id="co-city"
                  className="form-control"
                  autoComplete="address-level2"
                  value={shippingAddress.city}
                  onChange={(e) => setShippingAddress((s) => ({ ...s, city: e.target.value }))}
                />
              </div>
              <div className="form-group">
                <label className="form-label" htmlFor="co-zip">
                  Postcode
                </label>
                <input
                  id="co-zip"
                  className="form-control"
                  autoComplete="postal-code"
                  value={shippingAddress.zipCode}
                  onChange={(e) => setShippingAddress((s) => ({ ...s, zipCode: e.target.value }))}
                />
              </div>
            </div>
            <div className="form-group">
              <label className="form-label" htmlFor="co-phone">
                Phone
              </label>
              <input
                id="co-phone"
                className="form-control"
                autoComplete="tel"
                value={shippingAddress.phone}
                onChange={(e) => setShippingAddress((s) => ({ ...s, phone: e.target.value }))}
              />
            </div>

            {!clientSecret && (
              <button
                type="button"
                className="btn btn-primary btn-full checkout-continue-btn"
                onClick={startPayment}
                disabled={creatingPi || !pk}
              >
                {creatingPi ? 'Preparing payment…' : 'Continue to payment'}
              </button>
            )}

            <p className="checkout-trust">
              <ShieldCheck size={16} strokeWidth={1.75} className="checkout-trust__icon" aria-hidden />
              Payments are processed by Stripe. We never store your full card number.
            </p>
          </div>

          <aside className="checkout-summary card-like">
            <h2 className="checkout-card-title">Order summary</h2>
            <ul className="checkout-lines">
              {cart.map((line) => (
                <li key={line.product?._id || line.product}>
                  <span>
                    {line.product?.name} × {line.quantity}
                  </span>
                  <span>
                    £{Number(line.lineTotal ?? (line.price || 0) * (line.quantity || 0)).toFixed(2)}
                  </span>
                </li>
              ))}
            </ul>
            <div className="summary-row">
              <span>Subtotal</span>
              <span>£{getSubtotal().toFixed(2)}</span>
            </div>
            {totals && (
              <>
                <div className="summary-row">
                  <span>Discount</span>
                  <span className="checkout-summary__discount">
                    −£{Number(totals.discountAmount || 0).toFixed(2)}
                  </span>
                </div>
                <div className="summary-row total">
                  <span>Total</span>
                  <span>£{Number(totals.total || 0).toFixed(2)}</span>
                </div>
              </>
            )}
            <button type="button" className="btn btn-outline btn-sm checkout-edit-cart" onClick={() => navigate('/cart')}>
              Edit cart
            </button>

            <p className="checkout-summary__lock">
              <Lock size={14} strokeWidth={1.75} aria-hidden />
              Encrypted checkout
            </p>

            {clientSecret && stripePromise && (
              <div className="checkout-stripe-wrap">
                <h3 className="checkout-subheading">Payment</h3>
                <Elements stripe={stripePromise} options={{ clientSecret }}>
                  <CheckoutPaymentForm shippingAddress={shippingAddress} onSuccess={handlePaidSuccess} />
                </Elements>
              </div>
            )}
          </aside>
        </div>
      </div>
    </main>
  );
}
